server {
    listen 80;
    server_name localhost;

    # Health check — returns a static 200 without touching upstream.
    # This is intentional: the ops team wanted a fast synthetic health probe
    # that doesn't depend on the Python backend being fully warmed up.
    location = /health {
        default_type application/json;
        return 200 '{"status":"ok"}';
    }

    # Reverse-proxy everything under /api/ to the Flask backend.
    location /api/ {
        proxy_pass http://127.0.0.1:

from flask import Flask, jsonify

app = Flask(__name__)


@app.route("/health")
def health():
    return jsonify({"status": "ok"})


@app.route("/api/data")
def api_data():
    return jsonify({
        "status": "ok",
        "items": [
            {"id": 1, "name": "widget-a", "price": 9.99},
            {"id": 2, "name": "widget-b", "price": 14.50},
            {"id": 3, "name": "widget-c", "price": 22.00},
        ],
    })


if __name__ == "__main__":
    app.run(host="127.0.0.1", port=5000)
